/**
 * Analytics data models for the dashboard API.
 *
 * Design: Composable types built from small building blocks.
 * - TimeSeriesPoint: atomic data point (timestamp + value)
 * - MetricSummary: aggregated view of a single metric with trend
 * - DashboardData: composite of multiple MetricSummary + time series
 * - AnalyticsQuery: standardized request parameters across all endpoints
 */

/**
 * Supported metric types for analytics queries.
 */
export type MetricType = 'orders' | 'revenue' | 'users' | 'conversion';

/**
 * Time granularity for time-series data.
 */
export type TimeGranularity = 'hour' | 'day' | 'week' | 'month';

/**
 * A single data point in a time series.
 */
export interface TimeSeriesPoint {
  timestamp: Date;
  value: number;
  label?: string;
}

/**
 * Aggregated summary of a single metric, including trend comparison.
 */
export interface MetricSummary {
  metricType: MetricType;
  current: number;
  previous: number;
  changePercent: number;
  trend: 'up' | 'down' | 'flat';
  timeSeries: TimeSeriesPoint[];
}

/**
 * Date range for analytics queries.
 */
export interface DateRange {
  start: Date;
  end: Date;
}

/**
 * Standardized query parameters for all analytics endpoints.
 */
export interface AnalyticsQuery {
  dateRange: DateRange;
  granularity: TimeGranularity;
  metricType?: MetricType;
}

/**
 * Full dashboard response containing all key metrics.
 */
export interface DashboardData {
  generatedAt: Date;
  dateRange: DateRange;
  metrics: {
    orders: MetricSummary;
    revenue: MetricSummary;
    users: MetricSummary;
    conversion: MetricSummary;
  };
  recentActivity: ActivityEntry[];
}

/**
 * A single activity entry for the dashboard feed.
 */
export interface ActivityEntry {
  id: string;
  type: 'order_created' | 'order_status_changed' | 'user_created';
  description: string;
  timestamp: Date;
}

/**
 * Response shape for the reports/summary endpoint.
 */
export interface ReportSummary {
  dateRange: DateRange;
  generatedAt: Date;
  totals: {
    orders: number;
    revenue: number;
    newUsers: number;
    averageOrderValue: number;
  };
  topMetrics: MetricSummary[];
}

/**
 * Calculate the trend direction from a percentage change.
 */
export function calculateTrend(changePercent: number): 'up' | 'down' | 'flat' {
  if (changePercent > 0.5) return 'up';
  if (changePercent < -0.5) return 'down';
  return 'flat';
}

/**
 * Calculate percentage change between two values.
 * Returns 0 if the previous value is 0 to avoid division by zero.
 */
export function calculateChangePercent(current: number, previous: number): number {
  if (previous === 0) return current > 0 ? 100 : 0;
  return ((current - previous) / previous) * 100;
}

/**
 * Repository for analytics data access.
 *
 * Provides read-only aggregation queries over order and user data.
 * Unlike other repositories, this does NOT extend BaseRepository because
 * analytics are derived/computed, not stored as their own collection.
 *
 * Implementation note for downstream developers:
 * The methods here are stubs returning placeholder data. Implement them
 * by querying the 'orders' and 'users' collections from the Database,
 * then aggregating in-memory. For a production system, these would be
 * database-level aggregation queries.
 */

import type { Database } from '../utils/database.js';
import type {
  MetricType,
  DateRange,
  TimeGranularity,
  TimeSeriesPoint,
} from '../models/analytics.js';
import { Logger } from '../utils/logger.js';

export interface AggregatedMetric {
  total: number;
  previousTotal: number;
  timeSeries: TimeSeriesPoint[];
}

export class AnalyticsRepository {
  private logger = new Logger('Repository:analytics');

  constructor(private db: Database) {}

  /**
   * Count orders within a date range.
   *
   * TODO: Implement by querying the 'orders' collection and filtering
   * by createdAt within the date range.
   */
  countOrders(dateRange: DateRange): AggregatedMetric {
    this.logger.debug(`Counting orders for range: ${dateRange.start.toISOString()} - ${dateRange.end.toISOString()}`);
    return this.placeholderMetric();
  }

  /**
   * Sum revenue within a date range.
   *
   * TODO: Implement by summing order.total for orders within the date range.
   */
  sumRevenue(dateRange: DateRange): AggregatedMetric {
    this.logger.debug(`Summing revenue for range: ${dateRange.start.toISOString()} - ${dateRange.end.toISOString()}`);
    return this.placeholderMetric();
  }

  /**
   * Count new users within a date range.
   *
   * TODO: Implement by querying the 'users' collection and filtering
   * by createdAt within the date range.
   */
  countNewUsers(dateRange: DateRange): AggregatedMetric {
    this.logger.debug(`Counting new users for range: ${dateRange.start.toISOString()} - ${dateRange.end.toISOString()}`);
    return this.placeholderMetric();
  }

  /**
   * Build a time series for a given metric within a date range.
   *
   * TODO: Implement by bucketing data points according to the granularity.
   * For example, 'day' granularity should group by calendar date.
   */
  getTimeSeries(
    metricType: MetricType,
    dateRange: DateRange,
    granularity: TimeGranularity,
  ): TimeSeriesPoint[] {
    this.logger.debug(`Building time series: ${metricType}, granularity=${granularity}`);
    void dateRange;
    return [];
  }

  /**
   * Get recent activity entries (order creations, status changes, user signups).
   *
   * TODO: Implement by merging and sorting recent entries from orders and users
   * collections, limited to the specified count.
   */
  getRecentActivity(limit: number): Array<{
    type: 'order_created' | 'order_status_changed' | 'user_created';
    entityId: string;
    timestamp: Date;
  }> {
    this.logger.debug(`Fetching recent activity, limit=${limit}`);
    return [];
  }

  private placeholderMetric(): AggregatedMetric {
    return { total: 0, previousTotal: 0, timeSeries: [] };
  }
}

/**
 * Analytics service — business logic for the analytics dashboard.
 *
 * Depends on:
 * - AnalyticsRepository (data layer) for aggregation queries
 *
 * Architecture note: This service orchestrates data from the analytics
 * repository into the response shapes defined in models/analytics.ts.
 * It does NOT directly query the Database — all data access goes through
 * the repository, consistent with the rest of the codebase.
 *
 * Implementation guide for downstream developers:
 * 1. First implement AnalyticsRepository methods (they currently return placeholders)
 * 2. Then the methods in this service will compose those results into API responses
 * 3. The route handlers call these service methods directly
 */

import type {
  AnalyticsQuery,
  DashboardData,
  MetricSummary,
  MetricType,
  ReportSummary,
  ActivityEntry,
  DateRange,
} from '../models/analytics.js';
import { calculateChangePercent, calculateTrend } from '../models/analytics.js';
import type { AnalyticsRepository } from '../repositories/analytics.repository.js';
import { Logger } from '../utils/logger.js';

export class AnalyticsService {
  private logger = new Logger('AnalyticsService');

  constructor(private analyticsRepository: AnalyticsRepository) {}

  /**
   * Build the full dashboard response with all key metrics.
   *
   * This is the primary endpoint for the dashboard view. It aggregates
   * orders, revenue, users, and conversion metrics for the given date range,
   * plus a recent activity feed.
   */
  getDashboard(query: AnalyticsQuery): DashboardData {
    this.logger.info('Building dashboard data');

    const { dateRange, granularity } = query;

    return {
      generatedAt: new Date(),
      dateRange,
      metrics: {
        orders: this.getMetric('orders', dateRange, granularity),
        revenue: this.getMetric('revenue', dateRange, granularity),
        users: this.getMetric('users', dateRange, granularity),
        conversion: this.getMetric('conversion', dateRange, granularity),
      },
      recentActivity: this.getRecentActivity(10),
    };
  }

  /**
   * Get a single metric summary with time series data.
   *
   * Used by both the dashboard (internally) and the per-metric endpoint.
   */
  getMetric(
    metricType: MetricType,
    dateRange: DateRange,
    granularity: AnalyticsQuery['granularity'],
  ): MetricSummary {
    this.logger.info(`Computing metric: ${metricType}`);

    const aggregated = this.fetchAggregatedData(metricType, dateRange);
    const timeSeries = this.analyticsRepository.getTimeSeries(
      metricType,
      dateRange,
      granularity,
    );

    const changePercent = calculateChangePercent(
      aggregated.total,
      aggregated.previousTotal,
    );

    return {
      metricType,
      current: aggregated.total,
      previous: aggregated.previousTotal,
      changePercent,
      trend: calculateTrend(changePercent),
      timeSeries,
    };
  }

  /**
   * Generate a summary report for the given date range.
   */
  getReportSummary(query: AnalyticsQuery): ReportSummary {
    this.logger.info('Generating report summary');

    const { dateRange, granularity } = query;
    const ordersMetric = this.getMetric('orders', dateRange, granularity);
    const revenueMetric = this.getMetric('revenue', dateRange, granularity);
    const usersMetric = this.getMetric('users', dateRange, granularity);

    const averageOrderValue =
      ordersMetric.current > 0
        ? revenueMetric.current / ordersMetric.current
        : 0;

    return {
      dateRange,
      generatedAt: new Date(),
      totals: {
        orders: ordersMetric.current,
        revenue: revenueMetric.current,
        newUsers: usersMetric.current,
        averageOrderValue,
      },
      topMetrics: [ordersMetric, revenueMetric, usersMetric],
    };
  }

  /**
   * Fetch aggregated data for a metric type from the repository.
   */
  private fetchAggregatedData(metricType: MetricType, dateRange: DateRange) {
    switch (metricType) {
      case 'orders':
        return this.analyticsRepository.countOrders(dateRange);
      case 'revenue':
        return this.analyticsRepository.sumRevenue(dateRange);
      case 'users':
        return this.analyticsRepository.countNewUsers(dateRange);
      case 'conversion': {
        // Conversion = orders / users. Derived from the other two metrics.
        const orders = this.analyticsRepository.countOrders(dateRange);
        const users = this.analyticsRepository.countNewUsers(dateRange);
        const total = users.total > 0 ? orders.total / users.total : 0;
        const previousTotal =
          users.previousTotal > 0
            ? orders.previousTotal / users.previousTotal
            : 0;
        return { total, previousTotal, timeSeries: [] };
      }
    }
  }

  /**
   * Get recent activity entries for the dashboard feed.
   */
  private getRecentActivity(limit: number): ActivityEntry[] {
    const raw = this.analyticsRepository.getRecentActivity(limit);
    return raw.map((entry, index) => ({
      id: `activity-${index}`,
      type: entry.type,
      description: this.describeActivity(entry.type, entry.entityId),
      timestamp: entry.timestamp,
    }));
  }

  private describeActivity(
    type: ActivityEntry['type'],
    entityId: string,
  ): string {
    switch (type) {
      case 'order_created':
        return `New order created: ${entityId}`;
      case 'order_status_changed':
        return `Order status updated: ${entityId}`;
      case 'user_created':
        return `New user registered: ${entityId}`;
    }
  }
}

/**
 * Analytics route handlers.
 *
 * Route structure:
 *   GET /api/analytics/dashboard       — full dashboard with all metrics
 *   GET /api/analytics/metrics/:type   — single metric detail (orders|revenue|users|conversion)
 *   GET /api/analytics/reports/summary — time-bounded aggregate report
 *
 * These handlers are framework-agnostic: they accept parsed query params and
 * return typed response objects. A framework adapter (Express, Fastify, etc.)
 * should call these handlers after parsing/validating the request.
 *
 * Query parameters (common to all endpoints):
 *   startDate  — ISO 8601 date string (required)
 *   endDate    — ISO 8601 date string (required)
 *   granularity — 'hour' | 'day' | 'week' | 'month' (default: 'day')
 */

import type { AnalyticsService } from '../services/analytics.service.js';
import type {
  AnalyticsQuery,
  DashboardData,
  MetricSummary,
  MetricType,
  ReportSummary,
  TimeGranularity,
} from '../models/analytics.js';

const VALID_METRIC_TYPES: MetricType[] = ['orders', 'revenue', 'users', 'conversion'];
const VALID_GRANULARITIES: TimeGranularity[] = ['hour', 'day', 'week', 'month'];

/**
 * Raw query parameters as they arrive from the HTTP layer.
 */
export interface AnalyticsQueryParams {
  startDate: string;
  endDate: string;
  granularity?: string;
}

/**
 * Standardized API response envelope.
 */
export interface ApiResponse<T> {
  success: boolean;
  data?: T;
  error?: string;
}

/**
 * Parse and validate raw query parameters into a typed AnalyticsQuery.
 * Throws on invalid input.
 */
export function parseAnalyticsQuery(params: AnalyticsQueryParams): AnalyticsQuery {
  if (!params.startDate || !params.endDate) {
    throw new Error('startDate and endDate are required');
  }

  const start = new Date(params.startDate);
  const end = new Date(params.endDate);

  if (isNaN(start.getTime()) || isNaN(end.getTime())) {
    throw new Error('startDate and endDate must be valid ISO 8601 dates');
  }

  if (start >= end) {
    throw new Error('startDate must be before endDate');
  }

  const granularity = (params.granularity ?? 'day') as TimeGranularity;
  if (!VALID_GRANULARITIES.includes(granularity)) {
    throw new Error(`Invalid granularity. Must be one of: ${VALID_GRANULARITIES.join(', ')}`);
  }

  return {
    dateRange: { start, end },
    granularity,
  };
}

/**
 * Validate a metric type parameter.
 */
export function parseMetricType(type: string): MetricType {
  if (!VALID_METRIC_TYPES.includes(type as MetricType)) {
    throw new Error(`Invalid metric type. Must be one of: ${VALID_METRIC_TYPES.join(', ')}`);
  }
  return type as MetricType;
}

/**
 * Analytics route handler class.
 *
 * Framework-agnostic: instantiate with an AnalyticsService, then call
 * the handler methods from your framework's route definitions.
 */
export class AnalyticsRouteHandler {
  constructor(private analyticsService: AnalyticsService) {}

  /**
   * GET /api/analytics/dashboard
   *
   * Returns the full dashboard view with all metrics and recent activity.
   */
  getDashboard(params: AnalyticsQueryParams): ApiResponse<DashboardData> {
    try {
      const query = parseAnalyticsQuery(params);
      const data = this.analyticsService.getDashboard(query);
      return { success: true, data };
    } catch (error) {
      return { success: false, error: (error as Error).message };
    }
  }

  /**
   * GET /api/analytics/metrics/:type
   *
   * Returns a single metric summary with time series data.
   * :type must be one of: orders, revenue, users, conversion
   */
  getMetric(
    metricTypeParam: string,
    params: AnalyticsQueryParams,
  ): ApiResponse<MetricSummary> {
    try {
      const metricType = parseMetricType(metricTypeParam);
      const query = parseAnalyticsQuery(params);
      const data = this.analyticsService.getMetric(
        metricType,
        query.dateRange,
        query.granularity,
      );
      return { success: true, data };
    } catch (error) {
      return { success: false, error: (error as Error).message };
    }
  }

  /**
   * GET /api/analytics/reports/summary
   *
   * Returns an aggregate report for the specified date range.
   */
  getReportSummary(params: AnalyticsQueryParams): ApiResponse<ReportSummary> {
    try {
      const query = parseAnalyticsQuery(params);
      const data = this.analyticsService.getReportSummary(query);
      return { success: true, data };
    } catch (error) {
      return { success: false, error: (error as Error).message };
    }
  }
}

