+/**
+ * Analytics service — business logic for the analytics dashboard.
+ *
+ * Depends on:
+ * - AnalyticsRepository (data layer) for aggregation queries
+ *
+ * Architecture note: This service orchestrates data from the analytics
+ * repository into the response shapes defined in models/analytics.ts.
+ * It does NOT directly query the Database — all data access goes through
+ * the repository, consistent with the rest of the codebase.
+ *
+ * Implementation guide for downstream developers:
+ * 1. First implement AnalyticsRepository methods (they currently return placeholders)
+ * 2. Then the methods in this service will compose those results into API responses
+ * 3. The route handlers call these service methods directly
+ */
+
+import type {
+  AnalyticsQuery,
+  DashboardData,
+  MetricSummary,
+  MetricType,
+  ReportSummary,
+  ActivityEntry,
+  DateRange,
+} from '../models/analytics.js';
+import { calculateChangePercent, calculateTrend } from '../models/analytics.js';
+import type { AnalyticsRepository } from '../repositories/analytics.repository.js';
+import { Logger } from '../utils/logger.js';
+
+export class AnalyticsService {
+  private logger = new Logger('AnalyticsService');
+
+  constructor(private analyticsRepository: AnalyticsRepository) {}
+
+  /**
+   * Build the full dashboard response with all key metrics.
+   *
+   * This is the primary endpoint for the dashboard view. It aggregates
+   * orders, revenue, users, and conversion metrics for the given date range,
+   * plus a recent activity feed.
+   */
+  getDashboard(query: AnalyticsQuery): DashboardData {
+    this.logger.info('Building dashboard data');
+
+    const { dateRange, granularity } = query;
+
+    return {
+      generatedAt: new Date(),
+      dateRange,
+      metrics: {
+        orders: this.getMetric('orders', dateRange, granularity),
+        revenue: this.getMetric('revenue', dateRange, granularity),
+        users: this.getMetric('users', dateRange, granularity),
+        conversion: this.getMetric('conversion', dateRange, granularity),
+      },
+      recentActivity: this.getRecentActivity(10),
+    };
+  }
+
+  /**
+   * Get a single metric summary with time series data.
+   *
+   * Used by both the dashboard (internally) and the per-metric endpoint.
+   */
+  getMetric(
+    metricType: MetricType,
+    dateRange: DateRange,
+    granularity: AnalyticsQuery['granularity'],
+  ): MetricSummary {
+    this.logger.info(`Computing metric: ${metricType}`);
+
+    const aggregated = this.fetchAggregatedData(metricType, dateRange);
+    const timeSeries = this.analyticsRepository.getTimeSeries(
+      metricType,
+      dateRange,
+      granularity,
+    );
+
+    const changePercent = calculateChangePercent(
+      aggregated.total,
+      aggregated.previousTotal,
+    );
+
+    return {
+      metricType,
+      current: aggregated.total,
+      previous: aggregated.previousTotal,
+      changePercent,
+      trend: calculateTrend(changePercent),
+      timeSeries,
+    };
+  }
+
+  /**
+   * Generate a summary report for the given date range.
+   */
+  getReportSummary(query: AnalyticsQuery): ReportSummary {
+    this.logger.info('Generating report summary');
+
+    const { dateRange, granularity } = query;
+    const ordersMetric = this.getMetric('orders', dateRange, granularity);
+    const revenueMetric = this.getMetric('revenue', dateRange, granularity);
+    const usersMetric = this.getMetric('users', dateRange, granularity);
+
+    const averageOrderValue =
+      ordersMetric.current > 0
+        ? revenueMetric.current / ordersMetric.current
+        : 0;
+
+    return {
+      dateRange,
+      generatedAt: new Date(),
+      totals: {
+        orders: ordersMetric.current,
+        revenue: revenueMetric.current,
+        newUsers: usersMetric.current,
+        averageOrderValue,
+      },
+      topMetrics: [ordersMetric, revenueMetric, usersMetric],
+    };
+  }
+
+  /**
+   * Fetch aggregated data for a metric type from the repository.
+   */
+  private fetchAggregatedData(metricType: MetricType, dateRange: DateRange) {
+    switch (metricType) {
+      case 'orders':
+        return this.analyticsRepository.countOrders(dateRange);
+      case 'revenue':
+        return this.analyticsRepository.sumRevenue(dateRange);
+      case 'users':
+        return this.analyticsRepository.countNewUsers(dateRange);
+      case 'conversion': {
+        // Conversion = orders / users. Derived from the other two metrics.
+        const orders = this.analyticsRepository.countOrders(dateRange);
+        const users = this.analyticsRepository.countNewUsers(dateRange);
+        const total = users.total > 0 ? orders.total / users.total : 0;
+        const previousTotal =
+          users.previousTotal > 0
+            ? orders.previousTotal / users.previousTotal
+            : 0;
+        return { total, previousTotal, timeSeries: [] };
+      }
+    }
+  }
+
+  /**
+   * Get recent activity entries for the dashboard feed.
+   */
+  private getRecentActivity(limit: number): ActivityEntry[] {
+    const raw = this.analyticsRepository.getRecentActivity(limit);
+    return raw.map((entry, index) => ({
+      id: `activity-${index}`,
+      type: entry.type,
+      description: this.describeActivity(entry.type, entry.entityId),
+      timestamp: entry.timestamp,
+    }));
+  }
+
+  private describeActivity(
+    type: ActivityEntry['type'],
+    entityId: string,
+  ): string {
+    switch (type) {
+      case 'order_created':
+        return `New order created: ${entityId}`;
+      case 'order_status_changed':
+        return `Order status updated: ${entityId}`;
+      case 'user_created':
+        return `New user registered: ${entityId}`;
+    }
+  }
+}
